import React, { useEffect, useState } from 'react';
import './empresasPanel.css';

const EmpresasPanel = () => {
  const [empresas, setEmpresas] = useState([]);
  const [imagenLateral, setImagenLateral] = useState('');

  // Cargar empresas del backend
  useEffect(() => {
    fetch('http://localhost:3001/api/empresas') // Reemplaza con tu URL real
      .then(res => res.json())
      .then(data => setEmpresas(data))
      .catch(error => console.error('Error al cargar empresas:', error));
  }, []);

  // Cargar imagen lateral del backend
  useEffect(() => {
    fetch('http://localhost:3001/api/imagen-lateral') // Reemplaza con tu endpoint real
      .then(res => res.json())
      .then(data => setImagenLateral(data.url)) // debe devolver { url: '...' }
      .catch(error => console.error('Error al cargar imagen lateral:', error));
  }, []);

  return (
    <div className="empresas-panel-container">
      {/* Parte izquierda: imagen desde backend */}
      <div className="imagen-lateral">
        {imagenLateral && <img src={imagenLateral} alt="Imagen lateral" />}
      </div>

      {/* Parte derecha: lista de empresas */}
      <div className="empresas-panel">
        <h2 className="empresas-titulo">Empresas</h2>
        <div className="empresas-grid">
          {empresas.map((empresa, index) => (
            <div key={index} className="empresa-card">
              <img src={empresa.imagen} alt={empresa.nombre} className="empresa-imagen" />
              <h3 className="empresa-nombre">{empresa.nombre}</h3>
              <p className="empresa-descripcion">{empresa.descripcion}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default EmpresasPanel;
